INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (93,N'PS4',N'',N'幕末浪漫第二幕 月華の剣士 ～月に咲く華、散りゆく花～',1,N'"幕末浪漫第二幕 月華の剣士"',N'SNK',N'SNK',N'剣戟対戦格闘',N'1,000円',N'2016年5月25日(水)',N'幕末を舞台にした剣戟格闘ゲームの第2弾。PS4版ではクロスプレイやオンライン対戦に対応している。',N'https://game.snk-corp.co.jp/official/lastblade2/',N'（PS4 / PS Vitaクロスバイ）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (94,N'PS4',N'',N'餓狼 MARK OF THE WOLVES',1,N'"餓狼 MARK OF THE WOLVES"',N'SNK',N'SNK',N'対戦格闘',N'1,080円',N'2016年12月7日(水)',N'伝説の格闘ゲーム『餓狼伝説』シリーズの最後を飾る名作。新主人公ロック・ハワードを筆頭に世代交代した新世代の闘いが描かれる。',N'https://www.snk-corp.co.jp/official/garou/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (95,N'PS4',N'',N'カラドリウス ブレイズ',1,N'"カラドリウス ブレイズ"',N'モス',N'モス',N'縦スクロールシューティング',N'1,800円',N'2018年7月5日(木)',N'ゴシックホラーの世界観と、ダメージを受けると服が脱げる「羞恥ブレイク」システムが特徴の本格派シューティングゲーム。',N'https://mossjp.co.jp/caladrius_ps4/',N'（ダウンロード版価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (96,N'PS4',N'',N'Little Nightmares リトルナイトメア',1,N'"Little Nightmares リトルナイトメア"',N'バンダイナムコエンターテインメント',N'Tarsier Studios',N'サスペンスアドベンチャー',N'2,420円',N'2017年4月28日(金)',N'巨大な船舶「モウ」に囚われた少女シックスが、知恵と勇気で脱出を目指す。不気味で美しい世界観が魅力の作品。',N'https://ln.bn-ent.net/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (97,N'PS4',N'',N'THE DARK PICTURES: MAN OF MEDAN',1,N'"THE DARK PICTURES: MAN OF MEDAN"',N'バンダイナムコエンターテインメント',N'Supermassive Games',N'ホラー・アドベンチャー',N'3,520円',N'2019年12月5日(木)',N'幽霊船を舞台にしたシネマティックホラー。プレイヤーの選択が物語の結末、そして登場人物たちの生死を大きく左右する。',N'https://darkpictures-manofmedan.bn-ent.net/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (98,N'PS4',N'',N'STEINS;GATE 0',1,N'"STEINS;GATE 0"',N'MAGES.',N'MAGES./5pb.',N'想定科学アドベンチャー',N'7,800円',N'2015年12月10日(木)',N'『STEINS;GATE』の正統続編。岡部倫太郎が紅莉栖を救うのを諦めてしまった世界線での物語が描かれる。',N'http://steinsgate0.jp/',N'（価格は税別）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (99,N'PS4',N'◯',N'RIVE',1,N'"RIVE"',N'レイニーフロッグ',N'Two Tribes',N'360度シューティング',N'1,500円',N'2017年1月20日(金)',N'ハイスピードな戦闘とプラットフォームアクションが融合したシューティングゲーム。状況に合わせて機体をハックし、窮地を脱する。',N'http://www.rainyfrog.com/ja/game/rive',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (100,N'PS4',N'',N'ステレデン',1,N'"ステレデン"',N'レイニーフロッグ',N'Pixelnest Studio',N'ログライク2Dシューティング',N'1,300円',N'2016年10月27日(木)',N'毎回ランダムに生成される宇宙空間で戦う、ログライク要素を取り入れたシューティングゲーム。ドット絵によるド派手な演出が特徴。',N'http://www.rainyfrog.com/ja/game/steredenn',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (101,N'PS4',N'',N'ぎゃるガンヴォルト',1,N'"ぎゃるガンヴォルト"',N'インティ・クリエイツ',N'インティ・クリエイツ',N'2Dアクション',N'509円',N'2015年8月5日(水)',N'80年代のレトロなグラフィックとサウンドを再現したアクションゲーム。人気作のキャラクターたちが作品の枠を超えて共演する。',N'http://www.inti-creates.com/galgunvolt/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (102,N'PS4',N'',N'スーパータイムフォース ＵＬＴＲＡ',1,N'"スーパータイムフォース ＵＬＴＲＡ"',N'8-4 / Capybara Games',N'Capybara Games',N'タイムトラベル分身アクション',N'2,000円',N'2016年5月10日(火)',N'時間を巻き戻し、過去の自分たちと協力して戦うユニークなアクションゲーム。最大30人の自分たちが画面を埋め尽くす爽快感。',N'https://www.playstation.com/ja-jp/games/super-time-force-ultra/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (103,N'PS4',N'',N'Biomutant',1,N'"Biomutant"',N'THQ Nordic',N'Experiment 101',N'オープンワールドアクションRPG',N'7,590円',N'2021年5月25日(火)',N'文明崩壊後の世界を舞台にしたケモノ系オープンワールドRPG。近接攻撃、射撃、ミュータント能力を組み合わせた多彩な戦闘が楽しめる。',N'https://www.thqnordic.com/games/biomutant',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (104,N'PS5',N'',N'Biomutant',1,N'"Biomutant"',N'THQ Nordic',N'Experiment 101',N'オープンワールドアクションRPG',N'5,170円',N'2022年9月6日(火)',N'ケモノ系オープンワールドRPGのPS5版。ロード時間の短縮や高解像度化により、さらに快適な冒険が可能。',N'https://www.thqnordic.com/games/biomutant',N'（デジタル版価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (105,N'PS4',N'◯',N'DRIVECLUB™',1,N'"DRIVECLUB"',N'ソニー・コンピュータエンタテインメント',N'Evolution Studios',N'ソーシャルレーシング',N'6,372円',N'2014年10月9日(木)',N'クラブを結成し、仲間と共に世界中の絶景を走り抜ける。ネットワークを通じた記録の共有や競争が熱いソーシャル・レースゲーム。',N'',N'（パッケージ版価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (106,N'PS4',N'',N'KILLZONE® SHADOW FALL',1,N'"KILLZONE® SHADOW FALL"',N'ソニー・コンピュータエンタテインメント',N'Guerrilla Games',N'FPS',N'2,189円',N'2014年2月22日(土)',N'巨大な壁で分断された惑星ヴェクタを舞台に、秘密工作員となって敵地へ潜入する。美しく緻密なグラフィックが特徴のFPS。',N'https://www.playstation.com/ja-jp/games/killzone-shadow-fall/',N'（PlayStation Hits価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (107,N'PS4',N'◯',N'RESOGUN™',1,N'"RESOGUN"',N'ソニー・コンピュータエンタテインメント',N'Housemarque',N'シューティング',N'1,470円',N'2014年2月22日(土)',N'円筒形のステージを自在に飛び回り、敵を殲滅しながら人類を救出する。ボクセルで構築された緻密な破壊描写が圧観。',N'https://www.playstation.com/ja-jp/games/resogun/',N'（税込価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (108,N'PS4',N'',N'ホホクム™',1,N'"ホホクム"',N'ソニー・コンピュータエンタテインメント',N'Honeyslug',N'アクション/アート',N'1,200円',N'2014年8月13日(水)',N'目指すべき明確な目的もなく、不思議な世界を漂いながら周囲の反応を楽しむアート性の高いリラクゼーション・アクション。',N'https://www.playstation.com/ja-jp/games/hohokum/',N'（税別価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (109,N'PS4',N'◯',N'Bloodborne®',1,N'"Bloodborne"',N'ソニー・コンピュータエンタテインメント',N'フロム・ソフトウェア / JAPANスタジオ',N'アクションRPG',N'2,189円',N'2015年3月26日(木)',N'獣の病が蔓延する古都ヤーナムで「狩人」となって戦う。変形する武器や「リゲイン」システムによる戦略性の高い死闘が展開。',N'https://www.playstation.com/ja-jp/games/bloodborne/',N'（PlayStation Hits価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (110,N'PS4',N'◯',N'inFAMOUS™ Second Son',1,N'"inFAMOUS Second Son"',N'ソニー・コンピュータエンタテインメント',N'Sucker Punch Productions',N'アクションアドベンチャー',N'2,189円',N'2014年5月22日(木)',N'超能力に目覚めた青年デルシンが、抑圧された社会の中で己の運命を切り拓く。煙やネオンなど多彩な能力を駆使するオープンワールド。',N'https://www.playstation.com/ja-jp/games/infamous-second-son/',N'（ダウンロード版価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (111,N'PS4',N'◯',N'HELLDIVERS™',1,N'"HELLDIVERS"',N'ソニー・コンピュータエンタテインメント',N'Arrowhead Game Studios',N'アクションシューティング',N'2,160円',N'2015年3月5日(木)',N'エリート部隊「ヘルダイバー」の一員として、銀河の平和を守るため過酷な惑星へ降り立つ。誤射（フレンドリーファイア）が隣り合わせの協力プレイ型。',N'https://www.playstation.com/ja-jp/games/helldivers/',N'リストにPS Plusের記載あり。（税込価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (112,N'PS4',N'◯',N'GRAVITY DAZE®',1,N'"GRAVITY DAZE"',N'ソニー・コンピュータエンタテインメント',N'JAPANスタジオ / Bluepoint Games',N'重力アクション・アドベンチャー',N'5,292円',N'2015年12月10日(木)',N'記憶を失った少女キトゥンが、重力を自由に操り空中を駆け抜ける。重力落ちものアクションとしての唯一無二の体験。',N'https://www.playstation.com/ja-jp/games/gravity-daze/',N'（価格は税別）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (113,N'PS4',N'',N'リトルビッグプラネット™3',1,N'"リトルビッグプラネット 3"',N'ソニー・コンピュータエンタテインメント',N'Sumo Digital',N'アクション',N'5,900円',N'2014年12月4日(木)',N'リビッツと新たな3人の仲間たちが冒険を繰り広げる。ステージ作成機能が進化した、作って遊んで共有するプラットフォームアクション。',N'https://www.playstation.com/ja-jp/games/littlebigplanet-3/',N'（通常版パッケージ価格・税別）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (114,N'PS4',N'',N'Entwined™',1,N'"Entwined"',N'ソニー・コンピュータエンタテインメント',N'Pixelopus',N'フライトアクション/リズム',N'990円',N'2014年6月19日(木)',N'魚と鳥、二つの魂を同時に操り、一つの形へと昇華させる。独特のアートワークと音楽が融合した、幻想的なフライトアクション。',N'https://www.playstation.com/ja-jp/games/entwined/',N'（価格は税込）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (115,N'PS4',N'',N'風ノ旅ビト',1,N'"風ノ旅ビト"',N'ソニー・コンピュータエンタテインメント',N'thatgamecompany / SIEサンタモニカスタジオ',N'アドベンチャー',N'1,320円',N'2015年7月23日(木)',N'砂漠に覆われた文明の地を、どこまでも広がる世界を旅する。言葉を使わず、他者と心が通じ合う一期一会の交流が深い感動を呼ぶ。',N'https://www.playstation.com/ja-jp/games/journey/',N'（価格は税込）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (116,N'PS4',N'',N'ラチェット＆クランク® THE GAME',1,N'"ラチェット＆クランク THE GAME"',N'ソニー・インタラクティブエンタテインメント',N'Insomniac Games',N'アクションアドベンチャー',N'2,189円',N'2016年8月9日(火)',N'銀河を股に掛けるコンビの活躍を描く。ド派手なガラメカを使いこなし、多彩な惑星を冒険する爽快アクション。',N'https://www.playstation.com/ja-jp/games/ratchet-and-clank-the-game/',N'（PlayStation Hits価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (117,N'PS4',N'◯',N'バウンド：王国の欠片',1,N'"バウンド：王国の欠片"',N'ソニー・インタラクティブエンタテインメント',N'Plastic / SIEサンタモニカスタジオ',N'アクションアドベンチャー',N'2,200円',N'2016年8月16日(火)',N'バレエの動きをモチーフにした美しいアクションで、崩壊しつつある精神世界を進む。美しくも物哀しい物語と芸術的な演出が融合。',N'https://www.playstation.com/ja-jp/games/bound/',N'（価格は税込）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (118,N'PS4',N'◯',N'人喰いの大鷲トリコ®',1,N'"人喰いの大鷲トリコ"',N'ソニー・インタラクティブエンタテインメント',N'SIEジャパンスタジオ / ジェン・デザイン',N'アクションアドベンチャー',N'4,290円',N'2016年12月6日(火)',N'少年と巨獣「トリコ」の言葉を超えた絆を描く物語。巨大な遺跡を舞台に、協力し合って困難を乗り越える。',N'https://www.playstation.com/ja-jp/games/the-last-guardian/',N'（Value Selection価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (119,N'PS4',N'◯',N'ワンダと巨像®',1,N'"ワンダと巨像"',N'ソニー・インタラクティブエンタテインメント',N'Bluepoint Games / SIEジャパンスタジオ',N'アクションアドベンチャー',N'3,190円',N'2018年2月8日(木)',N'愛する少女を救うため、失われた地で16体の巨像に挑む。巨体にしがみつき、弱点を突くという手に汗握る死闘が展開。',N'https://www.playstation.com/ja-jp/games/shadow-of-the-colossus/',N'（Value Selection価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (120,N'PS4',N'◯',N'God of War',1,N'"God of War"',N'ソニー・インタラクティブエンタテインメント',N'SIEサンタモニカスタジオ',N'アクションアドベンチャー',N'1,990円',N'2018年4月20日(金)',N'かつての軍神クレイトスが、北欧神話の世界で息子アトレウスと共に旅をする。一発撮りのようなカメラワークと重厚なドラマが融合。',N'https://www.playstation.com/ja-jp/games/god-of-war/',N'（PlayStation Hits価格・税別）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (121,N'PS4',N'',N'StarBlood Arena',1,N'"StarBlood Arena"',N'ソニー・インタラクティブエンタテインメント',N'WhiteMoon Dreams',N'VRシューティングバトル',N'5,292円',N'2017年6月29日(木)',N'360度全方位が戦場となるVR専用シューティング。重力に縛られない自在な移動と、緊迫したオンライン対戦が魅力。',N'https://www.playstation.com/ja-jp/games/starblood-arena/',N'VR専用タイトル。',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (122,N'PS4',N'',N'STAR WARS ジェダイ：フォールン・オーダー™',1,N'"STAR WARS ジェダイ：フォールン・オーダー"',N'エレクトロニック・アーツ',N'Respawn Entertainment',N'アクションアドベンチャー',N'4,300円',N'2019年11月15日(金)',N'帝国に追われる若きジェダイ、カル・ケスティスとして生き残れ。ライトセーバーとフォースを駆使するタクティカルな戦闘が特徴。',N'https://www.ea.com/ja-jp/games/starwars/jedi-fallen-order',N'（EA BEST HITS価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (123,N'PS4',N'',N'Need for Speed™ Heat',1,N'"Need for Speed Heat"',N'エレクトロニック・アーツ',N'Ghost Games',N'オープンワールド・レースゲーム',N'8,657円',N'2019年11月8日(金)',N'昼は合法なレースで稼ぎ、夜は違法なストリートレースで名声を高める。警察との熾烈な追走劇が楽しめる。',N'https://www.ea.com/ja-jp/games/need-for-speed/need-for-speed-heat',N'（ダウンロード版価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (124,N'PS5',N'',N'STAR WARS ジェダイ：フォールン・オーダー™',1,N'"STAR WARS ジェダイ：フォールン・オーダー"',N'エレクトロニック・アーツ',N'Respawn Entertainment',N'アクションアドベンチャー',N'4,300円',N'2021年6月11日(金)',N'帝国に追われる若きジェダイ、カル・ケスティスとして生き残れ。PS5版では解像度やフレームレートの向上、ロード時間の短縮が図られている。',N'https://www.ea.com/ja-jp/games/starwars/jedi-fallen-order',N'（EA BEST HITS価格）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (125,N'PS4',N'',N'Aaero',1,N'"Aaero"',N'Wired Productions',N'Mad Fellows',N'アクション/音楽',N'1,731円',N'2018年1月9日(火)',N'スタイリッシュなSF世界を舞台に、音楽とシンクロして光のレールを駆け抜ける。迫力の重低音とハイスピードなアクションが融合。',N'https://www.wiredproductions.com/games/aaero/',N'（1,574円+税）',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (126,N'PS4',N'',N'LIMBO',1,N'"LIMBO"',N'Playdead',N'Playdead',N'アクション/パズル',N'1,222円',N'2015年12月2日(水)',N'モノトーンで描かれる幻想的かつ不気味な世界を、妹を探して進む少年。死と隣り合わせの罠を解き明かす、独特の没入感を持つパズル。',N'https://playdead.com/games/limbo/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (127,N'PS4',N'',N'Table Top Racing: World Tour',1,N'"Table Top Racing: World Tour"',N'Playrise Digital Ltd.',N'Playrise Digital Ltd.',N'コンバットレーシング',N'1,800円',N'2016年5月3日(火)',N'テーブルの上がサーキットになる、多種多様な小型車によるレース。武器を駆使してライバルを蹴散らし、白熱のバトルを展開。',N'https://www.playrise-digital.com/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (128,N'PS4',N'',N'The Swapper',1,N'"The Swapper"',N'Curve Digital',N'Facepalm Games',N'パズルアクションアドベンチャー',N'2,000円',N'2015年11月3日(火)',N'自分自身のクローンを作成し、意識を移し替えながら進むSFパズル。クレイ（粘土）モデルによる独特のグラフィックが特徴。',N'http://facepalmgames.com/the-swapper/',N'',N'◯',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (129,N'PS4',N'',N'Ｒ４　リッジ・レーサー・タイプ４',1,N'"R4 RIDGE RACER TYPE 4"',N'バンダイナムコエンターテインメント',N'ナムコ',N'レース',N'1,100円',N'2023年3月21日(火)',N'PSの名作がリバイバル。4つのチーム、4つのメーカーが織りなすグランプリを制。洗練されたビジュアルとBGMが今も色褪せない。',N'https://www.bandainamcoent.co.jp/cs/list/ridge4/',N'クラシックスカタログ対応。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (130,N'PS5',N'',N'Ｒ４　リッジ・レーサー・タイプ４',1,N'"R4 RIDGE RACER TYPE 4"',N'バンダイナムコエンターテインメント',N'ナムコ',N'レース',N'1,100円',N'2023年3月21日(火)',N'名作レースゲームのPS5版。巻き戻し、クイックセーブ、カスタムビデオフィルタなどの新機能により、さらに遊びやすく進化。',N'https://www.bandainamcoent.co.jp/cs/list/ridge4/',N'クラシックスカタログ対応。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (131,N'PS4',N'',N'Venus Vacation PRISM - DEAD OR ALIVE Xtreme -',1,N'"Venus Vacation PRISM - DEAD OR ALIVE Xtreme -"',N'コーエーテクモゲームス',N'コーエーテクモゲームス',N'イマーシブ恋愛アドベンチャー',N'7,480円',N'2025年3月27日(木)',N'ヴィーナス諸島で女の子たちとの甘いひとときを過ごす。シリーズ初の恋愛アドベンチャーとして、圧倒的な没入感を提供。',N'https://www.gamecity.ne.jp/vva_prism/',N'2025年3月27日発売。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (132,N'PS5',N'',N'Venus Vacation PRISM - DEAD OR ALIVE Xtreme -',1,N'"Venus Vacation PRISM - DEAD OR ALIVE Xtreme -"',N'コーエーテクモゲームス',N'コーエーテクモゲームス',N'イマーシブ恋愛アドベンチャー',N'7,480円',N'2025年3月27日(木)',N'女の子たちとの距離がこれまで以上に近づく、恋愛シミュレーション。PS5の高解像度グラフィックで彼女たちの輝きを描く。',N'https://www.gamecity.ne.jp/vva_prism/',N'2025年3月27日発売。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (133,N'PS4',N'',N'ユミアのアトリエ ～追憶の錬金術士と幻創の地～',1,N'"ユミアのアトリエ ～追憶の錬金術士と幻創の地～"',N'コーエーテクモゲームス',N'ガスト',N'錬金術RPG',N'8,580円',N'2025年3月21日(金)',N'滅びた大陸を舞台に、錬金術士ユミアが真実を追う。オープンなフィールドでの探索と、進化した錬金術システムが魅力。',N'https://atelier.games/yumia/jp/',N'2025年3月21日発売。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (134,N'PS5',N'',N'ユミアのアトリエ ～追憶の錬金術士と幻創の地～',1,N'"ユミアのアトリエ ～追憶の錬金術士と幻創の地～"',N'コーエーテクモゲームス',N'ガスト',N'錬金術RPG',N'9,680円',N'2025年3月21日(金)',N'錬金術が禁忌となった世界で、ユミアが失われた歴史の真実を追う。PS5版ではより高精細なグラフィックで広大な世界を冒険できる。',N'https://atelier.games/yumia/jp/',N'2025年3月21日発売。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (135,N'PS4',N'',N'ドラゴンクエストⅢ　そして伝説へ…',1,N'"ドラゴンクエスト 3"',N'スクウェア・エニックス',N'チュンソフト (オリジナル)',N'RPG',N'1,650円',N'2017年8月24日(木)',N'伝説の勇者ロトの物語が語られる、シリーズ屈指の傑作。パーティ編成や転職システム、広大な世界での冒険が楽しめる。',N'https://www.jp.square-enix.com/dq3/',N'スマホ版の移植。価格は税込。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (136,N'PS4',N'',N'ドラゴンクエストⅡ　悪霊の神々',1,N'"ドラゴンクエスト 2"',N'スクウェア・エニックス',N'チュンソフト (オリジナル)',N'RPG',N'935円',N'2017年8月10日(木)',N'前作から100年後の世界を舞台に、ロトの血を引く3人の王子・王女が破壊神シドーの復活を阻止するため旅立つ。',N'https://www.dqcont.jp/dq2/',N'スマホ版の移植。価格は税込。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (137,N'PS4',N'',N'ドラゴンクエスト',1,N'"ドラゴンクエスト"',N'スクウェア・エニックス',N'チュンソフト (オリジナル)',N'RPG',N'660円',N'2017年8月10日(木)',N'伝説はここから始まった。竜王にさらわれた王女を救い出し、闇に閉ざされた世界に光を取り戻すため、一人の勇者が立ち上がる。',N'https://www.dqcont.jp/dq1/',N'スマホ版の移植。価格は税込。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (138,N'PS4',N'',N'龍が如く８外伝 Pirates in Hawaii',1,N'"龍が如く 8 外伝"',N'セガ',N'龍が如くスタジオ',N'アクションアドベンチャー',N'6,930円',N'2025年2月21日(金)',N'真島吾朗がハワイの海へ！記憶を失った真島が海賊船の船長となり、ド派手なバトルと島々を巡る冒険を繰り広げる。',N'https://ryu-ga-gotoku.com/pirates/',N'2025年2月21日発売。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (139,N'PS5',N'◯',N'龍が如く８外伝 Pirates in Hawaii',1,N'"龍が如く 8 外伝"',N'セガ',N'龍が如くスタジオ',N'アクションアドベンチャー',N'6,930円',N'2025年2月21日(金)',N'「夜の帝王」真島吾朗が海賊に!? PS5版では次世代のアクション体験と、緻密に描画されたハワイの海を舞台にした物語が展開。',N'https://ryu-ga-gotoku.com/pirates/',N'2025年2月21日発売。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (140,N'PS4',N'',N'ヴァルキリープロファイル −レナス−',1,N'"ヴァルキリープロファイル Lenneth"',N'スクウェア・エニックス',N'トライエース (オリジナル)',N'RPG',N'2,750円',N'2022年12月22日(木)',N'北欧神話を舞台に、戦乙女レナスがエインフェリアを選定する物語。重厚なストーリーと、2Dアクションのような操作性の戦闘が魅力。',N'https://www.jp.square-enix.com/vpl/',N'PSP版ベースの移植。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (141,N'PS5',N'',N'ヴァルキリープロファイル −レナス−',1,N'"ヴァルキリープロファイル Lenneth"',N'スクウェア・エニックス',N'トライエース (オリジナル)',N'RPG',N'2,750円',N'2022年12月22日(木)',N'不朽の名作がPS5で登場。巻き戻し機能やクイックセーブ、さらには高解像度化により、さらに快適に神話の世界を追体験。',N'https://www.jp.square-enix.com/vpl/',N'PSP版ベースの移植。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (142,N'PS4',N'',N'Granblue Fantasy Versus: Rising',1,N'"Granblue Fantasy Versus: Rising"',N'Cygames',N'アークシステムワークス',N'対戦アクション＆パーティー',N'6,600円',N'2023年12月14日(木)',N'『グランブルーファンタジー』を題材とした対戦格闘の続編。格闘ゲーム要素に加え、最大30人で遊べるパーティーゲームも収録。',N'https://rising.granbluefantasy.jp/',N'フリーエディション（無料版）あり。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (143,N'PS5',N'',N'Granblue Fantasy Versus: Rising',1,N'"Granblue Fantasy Versus: Rising"',N'Cygames',N'アークシステムワークス',N'対戦アクション＆パーティー',N'6,600円',N'2023年12月14日(木)',N'全ての対戦格闘ゲームファンへ贈る、進化した『グラブル』対戦アクション。PS5版では滑らかな動作と高精細なビジュアルでバトルが楽しめる。',N'https://rising.granbluefantasy.jp/',N'フリーエディション（無料版）あり。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (144,N'PS5',N'',N'TEKKEN™8',1,N'"TEKKEN 8"',N'バンダイナムコエンターテインメント',N'バンダイナムコスタジオ / アリカ',N'3D対戦格闘',N'7,920円',N'2024年1月26日(金)',N'「鉄拳」シリーズ最新作。新システム「ヒートシステム」により、アグレッシブかつ手に汗握る究極のバトルが展開される。',N'https://tk8.tekken-official.jp/',N'「鉄拳」シリーズ最新作。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (145,N'PS5',N'◯',N'FINAL FANTASY VII REMAKE',1,N'"FINAL FANTASY VII REMAKE INTERGRADE"',N'スクウェア・エニックス',N'スクウェア・エニックス',N'RPG',N'9,878円',N'2021年6月10日(木)',N'FFVIIリメイクのPS5版。表現力の向上に加え、ユフィを主人公とした新規エピソード「EPISODE INTERmission」が追加されている。',N'https://www.jp.square-enix.com/ffvii_remake/',N'PS5 Pro Enhanced対応。PS5版「INTERGRADE」。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (146,N'PS5',N'',N'デスカムトゥルー',1,N'"Death Come True"',N'イザナギゲームズ',N'トゥーキョーゲームス',N'実写アドベンチャー',N'1,980円',N'2024年9月20日(金)',N'全編実写で展開される、映画とゲームが融合したインタラクティブ作品。選択によってストーリーが変化し、複数の結末が待っている。',N'https://deathcometrue.com/',N'本郷奏多主演。実写映画ゲーム。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (147,N'PS4',N'',N'√Letter ルートレター',1,N'"ルートレター"',N'角川ゲームス',N'角川ゲームス / ハイド',N'ミステリーアドベンチャー',N'4,800円',N'2016年6月16日(木)',N'島根県を舞台に、15年前のペンフレンドからの手紙の真相を追うミステリー。美しい風景と切ない物語が交錯する。',N'http://www.r-letter.com/',N'角川ゲームミステリー第一弾。',N'',N'');
