INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (211,N'PS4',N'',N'DEAD OR ALIVE 5 Last Round',1,N'"DOA5 ラストラウンド"',N'コーエーテクモゲームス',N'Team NINJA',N'3D対戦格闘',N'6,600円',N'2015年2月19日(木)',N'『DOA5』シリーズの集大成。新キャラの追加や「やわらかエンジン」の搭載により、究極の対戦が楽しめる。',N'https://www.gamecity.ne.jp/doa5/lastround/',N'シリーズ最終章。',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (212,N'PS4',N'',N'アンチャーテッドコレクション',1,N'"アンチャーテッド/エル・ドラドの秘宝"',N'SCE',N'',N'アクション',N'',N'',N'SCEとNaughty DogのPS4用「アンチャーテッドコレクション」。三部作リマスター版の各作品。密林・海の底・砂漠などを 舞台にトレジャーハンターのネイサン・ドレイクが遺跡を探索するアクションアドベンチャー。',N'',N'',N'',N'');
