INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (213,N'PS4',N'',N'Grand Theft Auto V',1,N'"GTA5"',N'ロックスター・ゲームス',N'Rockstar North',N'オープンワールドアクション',N'7,560円',N'2014年12月11日(木)',N'3人の主人公が織り成す壮大な犯罪ドラマ。PS4版ではビジュアルが大幅強化され、一人称視点モードも追加。',N'https://www.rockstargames.com/jp/gta-v',N'世界的大ヒット作.',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (214,N'PS4',N'',N'The Order: 1886',1,N'"ジ・オーダー 1886"',N'ソニー・インタラクティブエンタテインメント',N'Ready at Dawn',N'アクションアドベンチャー',N'6,490円',N'2015年2月20日(金)',N'19世紀末のロンドンを舞台に、騎士団と半人半獣の戦いを描く。映画と見紛う圧倒的なグラフィックが特徴。',N'https://www.playstation.com/ja-jp/games/the-order-1886/',N'映像美が話題のTPS風ADV。',N'',N'');
