INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (236,N'Vita/P',N'',N'Dies irae/Amantes amentes(ディエス・イレ/アマンテース・アーメンテース)',1,N'"Dies irae/Amantes amentes(ディエス・イレ/アマンテース・アーメンテース)"',N'ヴューズ',N'',N'AVG',N'',N'',N'ライアーソフトのビジュアルノベルのPSP版。第二次世界大戦末期のベルリンを舞台に、ナチスの魔術結社と神を宿した少年たちの壮絶な戦いを描く伝奇アクションノベル 。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (237,N'Vita/P',N'',N'うたわれるもの PORTABLE',1,N'"うたわれるもの PORTABLE"',N'アクアプラス',N'',N'SLG',N'',N'',N'リ ーフ/アクアプラスのシミュレーションRPG。仮面をつけた記憶のない青年ハクオロを主人公とした和風ファンタジーSRPG。仲間との絆と壮大な世界観が特徴のPSP版。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (238,N'Vita/P',N'',N'英雄伝説/空の軌跡 the 3rd',1,N'"英雄伝説/空の軌跡 the 3rd"',N'日本ファルコム',N'',N'RPG',N'',N'',N'日本ファルコムのRPG「空の軌跡」シリーズ第3作のPSP版。教会の執行者ケビン・グラハムを主人公に「星の扉」の謎と贖罪の旅を描く。軌跡シリーズ最高傑作との呼び声も高い作品。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (239,N'Vita/P',N'',N'想い出にかわる君/メモリーズオフ',1,N'"想い出にかわる君/メモリーズオフ"',N'MAGES.(5pb.)',N'',N'AVG',N'',N'',N'KIDのビジュアルノベル「メモリーズオフ」シリーズ第1作のPSP版。遠くに引っ越した幼馴染への思いと新たな出会いを描く恋愛アドベンチャー。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (240,N'Vita/P',N'',N'グランナイツヒストリー',1,N'"グランナイツヒストリー"',N'マーベラス',N'',N'RPG',N'',N'',N'ヴァニ ラウェアのPSP用シミュレーションRPG。3つの騎士団が争う世界で記録と歴史に名を刻むべく戦うキャラクターを育成するシミュレー ションゲーム。',N'',N'',N'',N'');
