INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (242,N'Vita/P',N'',N'クロスチャンネル',1,N'"クロスチャンネル"',N'サイバーフロント',N'',N'AVG',N'',N'',N'PSP版ビジュアルノベル。世界が繰り返す終末の7日間のループに閉じ込められた学生たちの物語を描く。繰り返しの中で変わるもの・変わらないも のを問う哲学的なノベル。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (243,N'Vita/P',N'',N'ゴッドイーター・バースト',1,N'"ゴッドイーター・バースト"',N'ナムコ',N'',N'アクション',N'',N'',N'バンダイナムコのアクションRPG。強化外骨格「ゴッドアーク」を装備したゴッドイーターとして巨大生物「アラガミ」と戦うPSP用ハンティングアクション。「神機」でアラガミを狩り人類の滅亡を防ぐ。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (244,N'Vita/P',N'',N'この青空に約束を/てのひらのらくえん',1,N'"この青空に約束を/てのひらのらくえん"',N'テイジイエル',N'',N'AVG',N'',N'',N'ういんどみるのPSP版ビジュアルノベル。離島の全寮制学校を舞台に、空の彼方に憧れる少年たちと少女たちの青春と恋愛を描く。',N'',N'',N'',N'');
