INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (248,N'Vita/P',N'',N'ダンガンロンパ',1,N'"ダンガンロンパ"',N'スパイク',N'',N'AVG',N'',N'',N'スパイクのPSP用推理アドベンチャー。「希望ヶ峰学園」に閉じ込められた高校生たちがモノクマに強いられるコロシアイゲームを描く。証拠を集め学級裁判で犯人を追い詰めるゲームシステムが斬新。',N'',N'',N'',N'');
