INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (250,N'Vita/P',N'',N'ティル・ナ・ノーグ/悠久の仁',1,N'"ティル・ナ・ノーグ/悠久の仁"',N'システムソフトアルファ',N'',N'RPG',N'',N'',N'',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (251,N'Vita/P',N'',N'ときめきメモリアル4',1,N'"ときめきメモリアル4"',N'コナミ',N'',N'SLG',N'',N'',N'コナミの恋愛シミ ュレーション「ときめきメモリアル」シリーズ第4作のPSP版。高校生活を送りながら複数のヒロインと交流し恋愛を育む。',N'',N'',N'',N'');
