INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (256,N'Vita/P',N'',N'ぷよぷよ!!',1,N'"ぷよぷよ!!"',N'セガ',N'',N'パズル',N'',N'',N'セガのぷよぷよシリーズ20周年記念作品のPSP版。歴代シリーズのルールを収録し、多彩なキャラクターと共に落ちものパズルを楽しめる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (257,N'Vita/P',N'',N'プリンセスクラウン',1,N'"プリンセスクラウン"',N'アトラス',N'',N'RPG',N'',N'',N'アトラスの2Dアク ションRPGのPSP版。王位継承者の少女グラティナが異界の敵と戦う美麗なグラフィックのアクションRPG。元々はセガサターン版の名 作をPSPに移植。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (258,N'Vita/P',N'',N'ベースボールスターズプロフェッショナル',1,N'"ベースボールスターズプロフェッショナル"',N'SNK',N'',N'スポーツ',N'',N'',N'SNKのPS1用リアル野球ゲーム「ベースボールスターズ」シリーズのPSP版。実在球団を使いながらリーグ戦を戦う本格野球ゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (259,N'Vita/P',N'',N'ぼくのなつやすみ2ポータブル/ナゾナゾ姉妹と沈没船の秘密！',1,N'"ぼくのなつやすみ2ポータブル/ナゾナ ゾ姉妹と沈没船の秘密！"',N'SCE',N'',N'AVG',N'',N'',N'ソニーの「ぼくのなつやすみ」シリーズ第2作のPSP版。小豆島の親戚の 家で昭和の夏休みを過ごす子供の日常を体験するのんびりとした雰囲気のゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (260,N'Vita/P',N'',N'ぼくのなつやすみ4/瀬戸内少年探偵団「ボクと秘密の地図」',1,N'"ぼくのなつやすみ4/瀬戸内少年探偵団「 ボクと秘密の地図」"',N'SCE',N'',N'AVG',N'',N'',N'ソニーの「ぼくのなつやすみ」シリーズ第4作のPSP版。瀬戸内海の離島に迷 い込んだ少年が夏休みを過ごす体験型ゲーム。謎の地図を巡る冒険が展開する。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (261,N'Vita/P',N'',N'みんなのゴルフポータブル2',1,N'"みんなのゴルフポータブル2"',N'SCE',N'',N'スポーツ',N'',N'',N'SCEJのゴルフゲームシリーズのPSP版第2作。親しみやすいキャラクターと直感的な操作でゴルフを楽しむスポーツゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (262,N'Vita/P',N'',N'メタルスラッグ',1,N'"メタルスラッグ"',N'SNK',N'',N'アクション',N'',N'',N'SNKのアーケード発祥の横スクロールシューティングゲームのPSP版。重火器で敵兵を蹴散らし戦車「スラッグ」を駆るスピーディなアクションシューティング 。',N'',N'',N'',N'');
