INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (291,N'Vita/A',N'',N'LSD',1,N'"LSD"',N'アスミックエース',N'',N'ETC',N'',N'',N'アスミック・エースのPS1用ドリームエミュレーター。実際の夢日記をもとにした幻想的な夢の世界を自由に歩き回る体験型ゲーム。シュールな映像とサウンドが独特の雰囲気を醸し出す。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (292,N'Vita/A',N'',N'MYST',1,N'"MYST"',N'サン電子',N'',N'AVG',N'',N'',N'サイアンのパズルアドベンチャー「MYST」のPS1版。謎の島MYSTに流れ着いたプレイヤーがメカニカルな仕掛けを解き明かしながら謎に迫るポイント&クリック型ADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (293,N'Vita/A',N'',N'QUIZなないろDREAM/虹色町の奇跡',1,N'"QUIZなないろDREAM/虹色町の奇跡"',N'カプコン',N'',N'ETC',N'',N'',N'デービーソフトのPS1用クイズゲーム「QUIZなないろDREAM」。7色の夢をモチーフにした恋愛要素を含むクイズゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (294,N'Vita/A',N'',N'R4/リッジレーサーTYPE4',1,N'"R4/リッジレーサーTYPE4"',N'ナムコ',N'',N'レース',N'',N'',N'ナムコのPS1用レーシングゲーム「リッジレーサー」シリーズ第4作。グランプリ形式のストーリーモードを新搭載し、美麗なグラフィックと洗練されたドリフトレーシングが楽しめる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (295,N'Vita/A',N'',N'R-TYPE DELTA',1,N'"R-TYPE DELTA"',N'アイレム',N'',N'シューティング',N'',N'',N'アイレムのPS1用横 スクロールシューティング「R-TYPE」シリーズの最終章。ビットを駆使した独自のシステムと暗い世界観が特徴のシリーズ完結作。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (296,N'Vita/A',N'',N'U.P.P',1,N'"U.P.P"',N'インターレックス',N'',N'パズル',N'',N'',N'',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (297,N'Vita/A',N'',N'アーク・ザ・ラッド',1,N'"アーク・ザ・ラッド"',N'SCE',N'',N'RPG',N'',N'',N'SCEJとG-Craftのシミュ レーションアドベンチャー「アーク・ザ・ラッド」シリーズ第1作のPS1版。自然と機械が共存する世界で、英雄と呼ばれる少年アークが仲間たちと旅に出る。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (298,N'Vita/A',N'',N'アーク・ザ・ラッド2',1,N'"アーク・ザ・ラッド2"',N'SCE',N'',N'RPG',N'',N'',N'SCEJのSRPG「アーク・ザ・ラッド」シリーズ第2作のPS1版。前作から3年後、盗賊エルクを新主人公に加え、大きく広がった世界で陰謀に立ち向かう。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (299,N'Vita/A',N'',N'アーク・ザ・ラッド3',1,N'"アーク・ザ・ラッド3"',N'SCE',N'',N'RPG',N'',N'',N'SCEJのSRPG「アーク・ザ・ラッド」シリーズ第3作のPS1版。シリーズの結末を描く完結編。新世代の主人公アルクが活躍する。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (300,N'Vita/A',N'',N'アインハンダー',1,N'"アインハンダー"',N'スクエニ',N'',N'シューティング',N'',N'',N'スクウェアのPS1用横スクロールシューティング。工業的でサイバーパンクなビジュアルと高品質なBGMが特徴の本格派シューティング。自機「アインハンダー」を操り敵の武器を奪いながら進む。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (301,N'Vita/A',N'',N'アクアノートの休日',1,N'"アクアノートの休日"',N'アートディンク',N'',N'SLG',N'',N'',N'アートディ ンクのPS1用海中探索ゲーム。水中スクーターを操り海の中を自由に泳ぎ回り、魚や珊瑚礁を観察する癒し系ゲーム。BGMも幻想的で高い評価を受けた。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (302,N'Vita/A',N'',N'アクアノートの休日2',1,N'"アクアノートの休日2"',N'アートディンク',N'',N'ETC',N'',N'',N'アートデ ィンクのPS1用海中探索ゲーム第2作。前作の世界観を引き継ぎ、さらに広大な海中世界を探索できる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (303,N'Vita/A',N'',N'悪魔城年代記/悪魔城ドラキュラ',1,N'"悪魔城年代記/悪魔城ドラキュラ"',N'コナミ',N'',N'アクション',N'',N'',N'コナミの「悪魔城ドラキュラ」シリーズのPS1版。MSX2版をベースにリメイクしたアクションゲーム。ドラキュラ城を攻略 するシリーズ正統派アクション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (304,N'Vita/A',N'',N'イース3/ワンダラーズ・フロム・イース',1,N'"イース3/ワンダラーズ・フロム・イース"',N'ハドソン',N'',N'RPG',N'',N'',N'日本ファルコムのアクションRPG「イース」シリーズ第3作のPS1版。アドルとドギが横スクロールで活躍する。友情と冒険を描いたシリーズでも特異な横スクロールアクションRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (305,N'Vita/A',N'',N'イース4/The Dawn of YS',1,N'"イース4/The Dawn of YS"',N'ハドソン',N'',N'RPG',N'',N'',N'HudsonのPS1版「イース4」。セルセタの樹海を舞台にアドルが少女レアと共に旅するアクションRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (306,N'Vita/A',N'',N'ヴァンパイアハンターEXエディション',1,N'"ヴァンパイアハンターEXエディション"',N'カプコン',N'',N'格 闘',N'',N'',N'カプコンのPS1用対戦格闘ゲーム「ヴァンパイア」シリーズの「ヴァンパイアハンター」EXエディション版。魔物や吸血鬼がキャラクターとして登場するダークファンタジー格闘ゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (307,N'Vita/A',N'',N'ウンジャマ・ラミー',1,N'"ウンジャマ・ラミー"',N'SCE',N'',N'音ゲー',N'',N'',N'SCEJとaOn-ShaのPS1用リズムゲーム。「パラッパラッパー」の世界観を引き継いだロックバンドゲーム。ラミーというキャラクターがライブを成功させるためにミニゲームをこなす。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (308,N'Vita/A',N'',N'エコーナイト',1,N'"エコーナイト"',N'フロムソフト',N'',N'AVG',N'',N'',N'フロム・ソフトウェアのPS1用ホラーアドベンチャー。幽霊が漂う豪華客船を舞台に、迷い込んだ男性が幽霊たちを成仏させながら謎を解くアドベンチャー。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (309,N'Vita/A',N'',N'エコーナイト#2/眠りの支配者',1,N'"エコーナイト#2/眠りの支配者"',N'フロムソフト',N'',N'AVG',N'',N'',N'フロム・ソフトウェアのPS1用ホラーアドベンチャー第2作。ホテルを舞台に「眠りの支配者」の謎を追うホラーADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (310,N'Vita/A',N'',N'エリーのアトリエ/ザールブルグの錬金術師2',1,N'"エリーのアトリエ/ザールブルグの錬金術師2"',N'ガスト',N'',N'RPG',N'',N'',N'ガストのアトリエシリーズ第2作のPS1版。ザールブルグの錬金術師学校を舞台に、少女エリーが錬金術の 修行をしながら仲間と共に成長するRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (311,N'Vita/A',N'',N'オズの魔法使い',1,N'"オズの魔法使い"',N'ガンホー',N'',N'RPG',N'',N'',N'PS1用アドベンチャーゲーム「オズの魔法使い」。童話「オズの魔法使い」の世界観をベースにしたアドベンチャーゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (312,N'Vita/A',N'',N'オレっ!トンバ',1,N'"オレっ!トンバ"',N'ガンホー',N'',N'アクション',N'',N'',N'モンスターランドのPS1用アクションアドベンチャー。豚人間に大切なものを奪われた野生児トンバが奪還の旅に出るコミカルなアクション。ユニークなト ラップシステムが特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (313,N'Vita/A',N'',N'俺の料理',1,N'"俺の料理"',N'SCE',N'',N'アクション',N'',N'',N'SCEJのPS1用料理ゲーム。プレイヤーがコックとなり、食材を仕入れ料理を作って評判の高いレストランを目指す料理シミュレーションゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (314,N'Vita/A',N'',N'風の丘公園にて',1,N'"風の丘公園にて"',N'トゥエンティワン',N'',N'AVG',N'',N'',N'',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (315,N'Vita/A',N'',N'かまいたちの夜/特別編',1,N'"かまいたちの夜/特別編"',N'チュンソフト',N'',N'AVG',N'',N'',N'チュン ソフトのPS1用サウンドノベル「かまいたちの夜」特別編版。クリスマスのスキーリゾートで起きる連続殺人事件を解くホラーミステ リー。多数のエンディングと「特別編」追加シナリオを収録。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (316,N'Vita/A',N'',N'川のぬし釣り/秘境を求めて',1,N'"川のぬし釣り/秘境を求めて"',N'マーベラスAQL',N'',N'RPG',N'',N'',N'ビクターのPS1用フィッシングRPG「川のぬし釣り」シリーズ第5作。秘境を旅しながら巨大な魚「ぬし」を釣ることを目指すフィッ シングRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (317,N'Vita/A',N'',N'ガンパレードマーチ',1,N'"ガンパレードマーチ"',N'SCE',N'',N'SLG',N'',N'',N'アルファ・システムのPS1用シミュレーションRPG。異星生命体「幻獣」の侵攻に抵抗するため召集された学生兵士たちの生活と戦闘を描く。自由度の高いシミュレーションと恋愛要素が融合した名作。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (318,N'Vita/A',N'',N'がんばれ森川くん2号',1,N'"がんばれ森川くん2号"',N'SCE',N'',N'SLG',N'',N'',N'SCEJのPS1用ゲーム。 人工生命「森川くん2号」を画面越しに観察し成長を見守る育成シミュレーション。当時のAI技術を駆使したペットゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (319,N'Vita/A',N'',N'ギルティギア/復刻版',1,N'"ギルティギア/復刻版"',N'アークシステムワークス',N'',N'格闘',N'',N'',N'アークシステムワークスの2D格闘ゲーム「ギルティギア」シリーズ原点のPS1版復刻版。ロック要素のある演出とユニークなキャラク ターが魅力の本格2D格闘。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (320,N'Vita/A',N'',N'キングスフィールド',1,N'"キングスフィールド"',N'フロムソフト',N'',N'RPG',N'',N'',N'フロム・ソフ トウェアのPS1用3DダンジョンRPG第1作。暗いダンジョンをリアルタイムで探索するハードな難易度の3DRPG。後の「キングスフィールド」シリーズ・「ダークソウル」の原点。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (321,N'Vita/A',N'',N'キングスフィールド2',1,N'"キングスフィールド2"',N'フロムソフト',N'',N'RPG',N'',N'',N'フロム・ソ フトウェアのPS1用3DダンジョンRPG第2作。広大な城を探索しながら謎を解く重厚な世界観のダンジョンRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (322,N'Vita/A',N'',N'キングスフィールド3',1,N'"キングスフィールド3"',N'フロムソフト',N'',N'RPG',N'',N'',N'フロム・ソ フトウェアのPS1用3DダンジョンRPG第3作。シリーズの完成度が高まった正統派ダンジョン探索RPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (323,N'Vita/A',N'',N'久遠の絆',1,N'"久遠の絆"',N'F.O.G',N'',N'AVG',N'',N'',N'レッドカンパニーのPS1用アドベンチャーゲ ーム。江戸時代と現代を行き来する神秘的なラブストーリーを描く。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (324,N'Vita/A',N'',N'クライムクラッカーズ2',1,N'"クライムクラッカーズ2"',N'SCE',N'',N'RPG',N'',N'',N'SCEJのPS1用アク ションゲーム「クライムクラッカーズ」シリーズ第2作。可愛らしいキャラクターが活躍するアクションゲームの続編。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (325,N'Vita/A',N'',N'クラッシュバンディクー',1,N'"クラッシュバンディクー"',N'SCE',N'',N'アクション',N'',N'',N'SCEJとNaughty DogのPS1用3Dアクションゲーム。コアラのクラッシュが箱を割り敵を倒しながら進む3Dプラットフォームアクション。西洋の 技術と日本のキャラクターゲームを融合させた名作。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (326,N'Vita/A',N'',N'クラッシュバンディクー3/ブッとび!世界一周',1,N'"クラッシュバンディクー3/ブッとび!世界一周"',N'SCE',N'',N'アクション',N'',N'',N'Naughty DogのPS1用3Dアクションシリーズ第3作。タイムマシンで時空を超え古代・未来・西部など世界各地を舞台に冒険する。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (327,N'Vita/A',N'',N'クラッシュバンディクーレーシング',1,N'"クラッシュバンディクーレーシング"',N'SCE',N'',N'レース',N'',N'',N'Naughty DogのPS1用カートレーシングゲーム「クラッシュバンディクー」のスピンオフ。クラッシュとバンディクーシリーズのキャラが登場するマリオカート風レーシング。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (328,N'Vita/A',N'',N'グラディウスII/GOFERの野望',1,N'"グラディウスII/GOFERの野望"',N'ハドソン',N'',N'シューティング',N'',N'',N'コナミの横スクロールシューティング「グラディウス」シリーズ第2作のPS1版。多彩なパワーアップとステージ構成で高 い評価を受けた名作シューティング。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (329,N'Vita/A',N'',N'くるりんPA!',1,N'"くるりんPA!"',N'SKYSEA',N'',N'パズル',N'',N'',N'SCEJのPS1用パズルゲーム「くるりんPA!」。回転する輪を使ってゴールを目指すユニークな操作のパズルアクション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (330,N'Vita/A',N'',N'クロックタワー/The First Fear',1,N'"クロックタワー/The First Fear"',N'サン電子',N'',N'AVG',N'',N'',N'ヒューマンのPS1用ホラーアドベンチャー「クロックタワー」シリーズ原点「ザ・ファーストフィア」。巨大ハサミを持つシザ ーマンに追われながら洋館から脱出するサバイバルホラーADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (331,N'Vita/A',N'',N'クロックタワー/ゴーストヘッド',1,N'"クロックタワー/ゴーストヘッド"',N'サン電子',N'',N'AVG',N'',N'',N'ヒューマンのPS1用ホラーADVシリーズ第3作。多重人格を持つ女性ロッテを主人公に、霊的な存在「スタニスラス」の謎に迫る サバイバルホラー。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (332,N'Vita/A',N'',N'クロックタワー2',1,N'"クロックタワー2"',N'サン電子',N'',N'AVG',N'',N'',N'ヒューマンのPS1用ホラ ーADVシリーズ第2作。前作から8年後、事件の生存者ジェニファーが再びシザーマンの恐怖に巻き込まれる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (333,N'Vita/A',N'',N'豪血寺一族/ちょっとだけ最強伝説',1,N'"豪血寺一族/ちょっとだけ最強伝説"',N'アトラス',N'',N'格闘',N'',N'',N'アトラスのPS1用格闘ゲーム「豪血寺一族」シリーズのコンピレーション「ちょっとだけ最強伝説」。独特のキャラクターが登場する個性的な格闘ゲームシリーズをまとめた作品。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (334,N'Vita/A',N'',N'ここ掘れ!プッカ',1,N'"ここ掘れ!プッカ"',N'SCE',N'',N'SLG',N'',N'',N'',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (335,N'Vita/A',N'',N'コットン・オリジナル',1,N'"コットン・オリジナル"',N'サクセス',N'',N'シューティング',N'',N'',N'サクセスのPS1用魔女っ子横スクロールシューティング「コットン」シリーズPS1版。おにぎりを求めて飛び回る魔女の少女コットンが主人公の明るいシューティングゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (336,N'Vita/A',N'',N'コットン100%',1,N'"コットン100%"',N'ハムスター',N'',N'シューティング',N'',N'',N'コットンシリー ズの続編。可愛らしいキャラクターとポップな雰囲気のシューティングゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (337,N'Vita/A',N'',N'コナミアンティークス/MSXコレクションVol.1',1,N'"コナミアンティークス/MSXコレクションVol.1"',N'コナ ミ',N'',N'ETC',N'',N'',N'コナミのMSXゲーム名作をPS1に移植したコンピレーション第1弾。MSX版の懐かしい名作タイトルをPS1で楽しめるコレクション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (338,N'Vita/A',N'',N'コナミアンティークス/MSXコレクションVol.2',1,N'"コナミアンティークス/MSXコレクションVol.2"',N'コナ ミ',N'',N'ETC',N'',N'',N'コナミのMSXゲーム名作をPS1に移植したコンピレーション第2弾。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (339,N'Vita/A',N'',N'サーカディア',1,N'"サーカディア"',N'SCE',N'',N'AVG',N'',N'',N'SCEJのPS1用縦スクロールシューティングゲーム「サーカディア」。宇宙を舞台にした本格的な縦シューティングゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (340,N'Vita/A',N'',N'サイキックフォース2',1,N'"サイキックフォース2"',N'タイトー',N'',N'格闘',N'',N'',N'タイトーのPS1用3D格闘ゲーム「サイキックフォース」シリーズ第2作。超能力者たちが空中を自由に飛び回りながら戦う独特の3D格闘ゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (341,N'Vita/A',N'',N'サガフロンティア',1,N'"サガフロンティア"',N'スクエニ',N'',N'RPG',N'',N'',N'スクウェアのPS1用RPG。7人の主人公それぞれの視点から語られるオムニバス形式のRPG。各主人公に異なるシナリオとシステムが用意された意欲作。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (342,N'Vita/A',N'',N'サモンナイト',1,N'"サモンナイト"',N'日本一',N'',N'SLG',N'',N'',N'バンプレストのPS1用シミュレー ションRPG「サモンナイト」シリーズ第1作。召喚師見習いの少年(少女)を主人公に、召喚獣と共に育つ育成SRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (343,N'Vita/A',N'',N'サモンナイト2',1,N'"サモンナイト2"',N'日本一',N'',N'SLG',N'',N'',N'バンプレストのPS1用SRPG「サ モンナイト」シリーズ第2作。前作の世界観を引き継ぎ、新たな主人公と召喚獣のストーリーを展開する。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (344,N'Vita/A',N'',N'サンダーフォースV/パーフェクトシステム',1,N'"サンダーフォースV/パーフェクトシステム"',N'トゥエンテ ィワン',N'',N'シューティング',N'',N'',N'テクノソフトのPS1用横スクロールシューティング「サンダーフォース」シリーズ第5作。高速スクロールと多彩な自機・武器システムが魅力の本格派シューティング。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (345,N'Vita/A',N'',N'ジャンピングフラッシュ',1,N'"ジャンピングフラッシュ"',N'SCE',N'',N'アクション',N'',N'',N'SCEJのPS1用3Dアクションゲーム。ロボットウサギ「ロビット」が主人公の一人称視点縦スクロール3Dアクション。真上から真下に降下しな がら戦う独特のゲームプレイ。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (346,N'Vita/A',N'',N'ジャンピングフラッシュ2/アロハ男爵大弱りの巻',1,N'"ジャンピングフラッシュ2/アロハ男爵大弱りの巻"',N'SCE',N'',N'アクション',N'',N'',N'SCEJのPS1用3Dアクション「ジャンピングフラッシュ」シリーズ第2作。バロン・アロハのコミカルな野望を阻止する一人称視点縦スクロールアクション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (347,N'Vita/A',N'',N'シルエットミラージュ/リプログラムド・ホープ',1,N'"シルエットミラージュ/リプログラムド・ホープ"',N'ハムスター',N'',N'アクション',N'',N'',N'トレジャーのPS1用2Dアクションシューティング。光の属性と闇の属性を切り替えな がら戦う独自のシステムを持つ2Dアクション。高い難易度と爽快なゲームプレイが評価された。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (348,N'Vita/A',N'',N'シルバー事件',1,N'"シルバー事件"',N'アスキー',N'',N'AVG',N'',N'',N'スーパー・スイープ(須田剛一)のPS1用アドベンチャーゲーム。銃殺事件を追う刑事を主人公にしたスタイリッシュなテキストADV。独特のビジュアル演出と難解なシナリオが特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (349,N'Vita/A',N'',N'真・女神転生',1,N'"真・女神転生"',N'アトラス',N'',N'RPG',N'',N'',N'アトラスのPS1用RPG「真・女神転生」シリーズ第1作。現代東京を舞台に悪魔を仲魔にしながら勢力対立に巻き込まれる主人公の物語を描くダークなRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (350,N'Vita/A',N'',N'真・女神転生2',1,N'"真・女神転生2"',N'アトラス',N'',N'RPG',N'',N'',N'アトラスのPS1用RPG「真・女神転生」シリーズ第2作。大地震後の東京を舞台に、サタンの覚醒を巡る戦いを描く。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (351,N'Vita/A',N'',N'新型くるりんPA!',1,N'"新型くるりんPA!"',N'SKYSEA',N'',N'パズル',N'',N'',N'SCEJのPS1用パズルゲーム「くるりんPA!」の続編「新型くるりんPA!」。回転する輪を使ったパズルアクションの新システムを追加した続編。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (352,N'Vita/A',N'',N'スーパーロボット大戦α',1,N'"スーパーロボット大戦α"',N'バンプレスト',N'',N'SLG',N'',N'',N'バンプレストのPS1用スパロボシリーズ「α」シリーズ第1作。ガンダムやエヴァンゲリオンなど多彩なロボットアニメのキャラが共演するシミュレーションRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (353,N'Vita/A',N'',N'スパイロ・ザ・ドラゴン',1,N'"スパイロ・ザ・ドラゴン"',N'SCE',N'',N'アクション',N'',N'',N'SCEAとInsomniac GamesのPS1用3Dアクション。小さな紫のドラゴン「スパイロ」が主人公で、クリスタルに閉じ込められた仲間のドラゴンを解放しながら3D世界を駆け回る。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (354,N'Vita/A',N'',N'ゼノギアス',1,N'"ゼノギアス"',N'スクエニ',N'',N'RPG',N'',N'',N'スクウェアのPS1用RPG。壮大なSF設定と哲学的テーマを持つ名作RPG。機械「ギア」を操って戦うバトルシステムと複雑な世界観・ストーリーが特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (355,N'Vita/A',N'',N'だんじょん商店会/伝説の剣はじめました',1,N'"だんじょん商店会/伝説の剣はじめました"',N'ガンホー',N'',N'SLG',N'',N'',N'セガのPS1用アクションRPG。商店街が地下ダンジョンの上に立っており、地下を攻略しながら地上の商店に売る武器を制作する独創的なシステムのゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (356,N'Vita/A',N'',N'チキチキちきん',1,N'"チキチキちきん"',N'サクセス',N'',N'パズル',N'',N'',N'',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (357,N'Vita/A',N'',N'ツイステッドメタル',1,N'"ツイステッドメタル"',N'SCE',N'',N'レース',N'',N'',N'SCEAのPS1用カーコ ンバットゲーム。武装した車両に乗り込み他の車両と戦う暴力的なカーアクションゲーム。PS1初期の人気タイトル。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (358,N'Vita/A',N'',N'デュープリズム',1,N'"デュープリズム"',N'スクエニ',N'',N'RPG',N'',N'',N'スクウェアのPS1用アクシ ョンRPG。2人の主人公(少年マグナス・少女クレア)からどちらか選んでプレイでき、視点によってストーリーが異なる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (359,N'Vita/A',N'',N'東京魔人學園剣風帖',1,N'"東京魔人學園剣風帖"',N'アスミックエース',N'',N'SLG',N'',N'',N'エンジェルスタジオのPS1用アドベンチャーRPG。東京を舞台に魔人の力に目覚めた高校生が悪の組織と戦う学園伝奇ゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (360,N'Vita/A',N'',N'ときめきメモリアル2',1,N'"ときめきメモリアル2"',N'コナミ',N'',N'SLG',N'',N'',N'コナミのPS1用恋 愛シミュレーションゲーム「ときめきメモリアル」シリーズ第2作。新しい学校を舞台に複数のヒロインと交流しながら恋愛を育む。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (361,N'Vita/A',N'',N'ときめきメモリアル2/EVSアペンドディスク',1,N'"ときめきメモリアル2/EVSアペンドディスク"',N'コナミ',N'',N'機能追加',N'',N'',N'「ときめきメモリアル2」用のアペンドディスク。本編に追加シナリオや特典要素を加えるディスク。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (362,N'Vita/A',N'',N'トンバ!ザ・ワイルドアドベンチャー',1,N'"トンバ!ザ・ワイルドアドベンチャー"',N'ガンホー',N'',N'アクション',N'',N'',N'モンスターランドのPS1用アクションアドベンチャー。「トンバ」とも呼ばれる野生児が豚一族との戦いを繰り広げる個性的なアクションゲーム。探索要素とクエストシステムが特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (363,N'Vita/A',N'',N'ネオアトラス',1,N'"ネオアトラス"',N'アートディンク',N'',N'SLG',N'',N'',N'アートディンクのPS1用 探検・地図作成シミュレーション。大航海時代を舞台に探検家を派遣し、伝説と事実が混在する世界地図を少しずつ完成させていく戦略ゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (364,N'Vita/A',N'',N'ネオアトラス2',1,N'"ネオアトラス2"',N'アートディンク',N'',N'SLG',N'',N'',N'アートディンクのPS1 用大航海地図作成シミュレーション「ネオアトラス」第2作。さらに広大な世界を舞台に探検家を派遣して地図を完成させる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (365,N'Vita/A',N'',N'ハームフルパーク',1,N'"ハームフルパーク"',N'SKYSEA',N'',N'シューティング',N'',N'',N'SCEJのPS1用シューティングゲーム。遊園地をモチーフにしたファンシーで独特のビジュアルと世界観を持つシューティングゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (366,N'Vita/A',N'',N'バイオハザード',1,N'"バイオハザード"',N'カプコン',N'',N'アクション',N'',N'',N'カプコンのPS1用サバイバルホラーゲームシリーズ第1作。ラクーン郊外の洋館に閉じ込められた特殊工作員がゾンビと戦いながら脱出を図る。ホラーゲ ームの名作として高い評価を受けた。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (367,N'Vita/A',N'',N'バイオハザード2',1,N'"バイオハザード2"',N'スクエニ',N'',N'アクション',N'',N'',N'カプコンのPS1用サバイバルホラー第2作。ゾンビが溢れるラクーンシティで警察官レオンと大学生クレアが脱出を試みる。傑作ホラーゲームとして高 い評価を誇る。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (368,N'Vita/A',N'',N'パズルボブル3DX',1,N'"パズルボブル3DX"',N'スクエニ',N'',N'パズル',N'',N'',N'タイトーのPS1用バブルシューティングパズルゲーム「パズルボブル」シリーズの3DX版。シャボン玉を撃って同色のシャボン玉を3個以上つなげて消すポップなパズルゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (369,N'Vita/A',N'',N'パネキット',1,N'"パネキット"',N'SCE',N'',N'ETC',N'',N'',N'SCEJのPS1用工作シミュレーション。パネルを組み合わせて自由にメカを作成し動かすユニークなクリエイティブゲーム。物理演算を利用したメカが水上・陸上・空中を動く。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (370,N'Vita/A',N'',N'パラサイト・イブ',1,N'"パラサイト・イブ"',N'スクエニ',N'',N'RPG',N'',N'',N'スクウェアのPS1用RPGホラー。NYの警察官アヤ・ブレアを主人公に、ミトコンドリアの覚醒による人類危機に立ち向かうバイオホラーRPG。映画「パラサイ ト・イブ」をゲーム化。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (371,N'Vita/A',N'',N'バロック▲シンドローム',1,N'"バロック▲シンドローム"',N'スティング',N'',N'AVG',N'',N'',N'スコアウェアとセガのPS1用ローグライクRPG。荒廃した世界でランダム生成されるダンジョンを探索し、自己の謎を解き明かすダークなRPG 。不条理な世界観が特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (372,N'Vita/A',N'',N'パンツァーバンディット',1,N'"パンツァーバンディット"',N'バンナム',N'',N'アクション',N'',N'',N'ウィンキーソフトのPS1用2Dアクションゲーム。複数のキャラクターを操作し多彩なアクションで進む横スクロールアクション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (373,N'Vita/A',N'',N'ひみつ戦隊メタモルV',1,N'"ひみつ戦隊メタモルV"',N'毎日コミュニケーションズ',N'',N'AVG',N'',N'',N'',N'',N'',N'',N'');
