INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (375,N'Vita/A',N'',N'ファイナルファンタジー7/インターナショナル',1,N'"ファイナルファンタジー7/インターナショナル"',N'ス クエニ',N'',N'RPG',N'',N'',N'スクウェアのPS1用RPG「ファイナルファンタジーVII」のインターナショナル版。追加ボス「ウェポン」や難易度調整などが加わった完全版。CGムービーと壮大なストーリーで革命をもたらした名作RPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (376,N'Vita/A',N'',N'ファイナルファンタジー9',1,N'"ファイナルファンタジー9"',N'スクエニ',N'',N'RPG',N'',N'',N'スクウェアのPS1用RPGシリーズ第9作。原点回帰をテーマにした剣と魔法のファンタジーRPG。クリスタルと魔法が息づく世界「ガイア」を舞台に、宿命に抗う人々の物語を描く。',N'',N'',N'',N'');
