INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (379,N'Vita/A',N'',N'ブレスオブファイア4/うつろわざるもの',1,N'"ブレスオブファイア4/うつろわざるもの"',N'カプコン',N'',N'RPG',N'',N'',N'カプコンのPS1用RPG「ブレスオブファイア」シリーズ第4作。竜の力を宿す青年リュウが旅を通じて己の本質と 向き合う。美しい墨絵調のグラフィックが特徴。',N'',N'',N'',N'');
