INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (384,N'Vita/A',N'',N'ポリスノーツ',1,N'"ポリスノーツ"',N'コナミ',N'',N'AVG',N'',N'',N'コナミ(小島秀夫)のPS1用グラフ ィックアドベンチャー。宇宙コロニー「ビヨンド・コーストの夢」を舞台にしたサスペンスADV。後のメタルギアにつながるコジプロ の世界観を持つ。',N'',N'',N'',N'');
