INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (386,N'Vita/A',N'',N'マールの国の人形姫',1,N'"マールの国の人形姫"',N'日本一',N'',N'RPG',N'',N'',N'日本一ソフトウェアのPS1用シミュレーションRPG。音楽が重要な役割を果たす独自のSRPGで、人形姫の物語を描く。コロロという精霊と共に戦う独創的なシステムが特徴。',N'',N'',N'',N'');
