INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (389,N'Vita/A',N'',N'マジック・カーペット',1,N'"マジック・カーペット"',N'エレクトロニック・アーツ',N'',N'シューティング',N'',N'',N'EAのPS1用3Dシューティングゲーム。魔法使いが魔法の絨毯に乗って空中戦を繰り広げるファンタジーシューティングゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (390,N'Vita/A',N'',N'まぼろし月夜',1,N'"まぼろし月夜"',N'シムス',N'',N'AVG',N'',N'',N'',N'',N'',N'',N'');
