INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (392,N'Vita/A',N'',N'マリオネットカンパニー2',1,N'"マリオネットカンパニー2"',N'ガンホー',N'',N'SLG',N'',N'',N'アートディンクのPS1用育成シミュレーション「マリオネットカンパニー」の続編。前作の世界観を引き継いだロボット育成シミュレーショ ン。',N'',N'',N'',N'');
