INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (400,N'Vita/A',N'',N'厄/友情談疑',1,N'"厄/友情談疑"',N'アイディアファクトリー',N'',N'AVG',N'',N'',N'SCEJのPS1用ホラ ーゲーム。不運を呼ぶ「厄」が主人公に降りかかり、それを他人に押し付けたり受け取ったりする独自システムを持つホラーゲーム。',N'',N'',N'',N'');
