INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (403,N'Vita/A',N'',N'ルナティックドーン・オデッセイ',1,N'"ルナティックドーン・オデッセイ"',N'アートディンク',N'',N'RPG',N'',N'',N'アスキーのPS1用オープンワールドRPG「ルナティックドーン」シリーズのPS1版「オデッセイ」。広大なフィールドを 自由に冒険できる先駆的なオープンエンド型RPG。',N'',N'',N'',N'');
