INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (406,N'Vita/A',N'',N'レイストーム',1,N'"レイストーム"',N'スクエニ',N'',N'シューティング',N'',N'',N'タイトーのPS1用縦スクロールシューティング。美麗な3Dグラフィックで描かれる「レイ」シリーズ第2弾。多連装レーザーやロック射撃などの爽快な攻 撃システムが特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (407,N'Vita/A',N'',N'レイマン',1,N'"レイマン"',N'ユービーアイ',N'',N'アクション',N'',N'',N'ユービーアイソフトのPS1用2Dアクションゲーム。手足のない独特のキャラクター「レイマン」が主人公の横スクロールプラットフォームアクション。美麗なグラフィックが特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (408,N'Vita/A',N'',N'レジェンド・オブ・ドラグーン',1,N'"レジェンド・オブ・ドラグーン"',N'アトラス',N'',N'RPG',N'',N'',N'SCEJのPS1用RPG。竜の力を持つ戦士「ドラグーン」を主人公に世界を救う旅を描く。ビジュアルの美しさとスケールの大きいストーリーが特徴の本格ファンタジーRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (409,N'Vita/A',N'',N'ロジック麻雀創龍/四人打ち・三人打ち',1,N'"ロジック麻雀創龍/四人打ち・三人打ち"',N'コナミ',N'',N'SLG',N'',N'',N'データイーストのPS1用麻雀ゲーム「ロジック麻雀創龍」。四人打ち・三人打ちの両方に対応したコンピューター麻 雀ゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (410,N'Vita/A',N'',N'ワイルドアームズ2ndイグニッション',1,N'"ワイルドアームズ2ndイグニッション"',N'SCE',N'',N'RPG',N'',N'',N'SCEJのPS1用RPG「ワイルドアームズ」シリーズ第2作。ファンタジーと西部劇を融合させた独特の世界観「フィルガイア」を舞台に、特殊能力者たちの戦いを描く。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (411,N'Vita/A',N'',N'悪魔城ドラキュラX/月下の夜想曲',1,N'"悪魔城ドラキュラX/月下の夜想曲"',N'コナミ',N'',N'アクション',N'',N'',N'コナミのPS1用アクションRPG。アルカードを主人公に広大なドラキュラ城を探索する2Dアクション。「探索型アクショ ン」の金字塔として高い評価を誇る。逆さまの城など独創的な要素が満載。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (412,N'Vita/A',N'',N'俺の屍を越えてゆけ',1,N'"俺の屍を越えてゆけ"',N'SCE',N'',N'PRG',N'',N'',N'SCEJのPS1用RPG。一族 が神に呪われ短命となった世界で、世代交代を繰り返しながら神を打ち倒すことを目指す独自のシステムが特徴。キャラ同士の恋愛で子を設け冒険者を育てる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (413,N'Vita/A',N'',N'学校であった怖い話S',1,N'"学校であった怖い話S"',N'バンプレスト',N'',N'AVG',N'',N'',N'バンプレストのPS1用ホラーADV。学校を舞台にした怪談を集めたホラーアドベンチャー。短編形式の怖い話をテキストで体験するサウンドノベル形式。',N'',N'',N'',N'');
