INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (418,N'Vita/A',N'',N'高橋名人の新冒険島',1,N'"高橋名人の新冒険島"',N'ハドソン',N'',N'アクション',N'',N'',N'ハドソン のPS1用アクションゲーム「高橋名人の冒険島」シリーズのPS1版。南国の島を舞台にした横スクロールアクションの新作。',N'',N'',N'',N'');
