INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (421,N'Vita/A',N'',N'信長秘録/下天の夢',1,N'"信長秘録/下天の夢"',N'アテナ',N'',N'AVG',N'',N'',N'コーエーのPS1用歴史 シミュレーション「信長秘録 下天の夢」。戦国時代を舞台に織田信長の視点から天下統一を目指すシミュレーションゲーム。',N'',N'',N'',N'');
