INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (424,N'Vita/A',N'',N'探偵神宮寺三郎/灯火が消えぬ間に',1,N'"探偵神宮寺三郎/灯火が消えぬ間に"',N'ワークジャム',N'',N'AVG',N'',N'',N'データイーストのPS1用推理ADV「探偵神宮寺三郎」シリーズのPS1版。灯火が消えるまでの夜を舞台にした謎の事件を 解くテキストADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (425,N'Vita/A',N'',N'超兄貴',1,N'"超兄貴"',N'ハドソン',N'',N'シューティング',N'',N'',N'メサイヤのPS1用横スクロールシューティングゲーム。超筋肉質の超人たちが登場するシュールなユーモアと独特の世界観を持つシューティングゲーム。個性的すぎるキャラクターが話題を呼んだ。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (426,N'Vita/A',N'',N'弟切草/蘇生篇',1,N'"弟切草/蘇生篇"',N'チュンソフト',N'',N'',N'',N'',N'チュンソフトのPS1用サ ウンドノベル「弟切草」シリーズ。山荘を舞台にしたホラーサウンドノベルの蘇生版。プレイヤーの選択でストーリーが分岐するマルチエンディング形式。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (427,N'Vita/A',N'',N'鉄拳2',1,N'"鉄拳2"',N'ナムコ',N'',N'格闘',N'',N'',N'ナムコのPS1用3D格闘ゲーム「鉄拳」シリーズ第2作。個性豊かなキャラクターと多彩な技が特徴の3D格闘ゲームシリーズ第2弾。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (428,N'Vita/A',N'',N'天外魔境II/MANJIMARU',1,N'"天外魔境II/MANJIMARU"',N'ハドソン',N'',N'PRG',N'',N'',N'ハドソンのPS1用RPG「天外魔境」シリーズ第2作のPS1移植版。和風の壮大な世界観と合戦を繰り広げる大河ファンタジーRPG。PC-E版の名作をPS1に移植。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (429,N'Vita/A',N'',N'東京魔人學園外法帖',1,N'"東京魔人學園外法帖"',N'アスミックエース',N'',N'SLG',N'',N'',N'エンジェルスタジオのPS1用ADV「東京魔人學園」シリーズの外伝作品。呪法を使う隠密剣士が主人公の伝奇アクションADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (430,N'Vita/A',N'',N'東京魔人學園朧綺譚',1,N'"東京魔人學園朧綺譚"',N'アスミックエース',N'',N'ETC',N'',N'',N'エンジェルスタジオのPS1用ADV「東京魔人學園」シリーズ。靄がかかった朧気な世界観を舞台にした伝奇アドベンチャーRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (431,N'Vita/A',N'',N'風のクロノア/door to phantomile',1,N'"風のクロノア/door to phantomile"',N'ナムコ',N'',N'アクション',N'',N'',N'ナムコのPS1用2.5D横スクロールアクション。夢の世界を舞台に、三角帽子の生き物クロノアが風の力を使いながら仲間を助ける旅を描く。感動的なストーリーと独特のゲームシステムが評価された。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (432,N'Vita/A',N'',N'風雨来記',1,N'"風雨来記"',N'F.O.G',N'',N'AVG',N'',N'',N'フォグのPS1用ドライブ&アドベンチャーゲ ーム。北海道をオートバイで旅しながら様々な人や景色と出会うドライブアドベンチャー。旅情あふれる雰囲気と自由なルート選択が特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (433,N'Vita/A',N'',N'牧場物語/ハーベストムーン',1,N'"牧場物語/ハーベストムーン"',N'マーベラス',N'',N'SLG',N'',N'',N'ビクターのPS1用牧場ゲーム「牧場物語」シリーズのPS1版「ハーベストムーン」。牧場を経営しながら村人と交流し恋愛も楽しむ農場シミュレーションRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (434,N'Vita/A',N'',N'牧場物語/ハーベストムーンfor ガール',1,N'"牧場物語/ハーベストムーンfor ガール"',N'マーベラス',N'',N'SLG',N'',N'',N'ビクターのPS1用「牧場物語」シリーズの女性主人公版「ハーベストムーン for ガール」。女性農場主として牧場を経営しながら村の男性と恋愛を楽しむ。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (435,N'Vita/A',N'',N'夢幻戦士ヴァリス',1,N'"夢幻戦士ヴァリス"',N'ハドソン',N'',N'アクション',N'',N'',N'日本テレネッ トのPS1用横スクロールアクション「夢幻戦士ヴァリス」シリーズのPS1版。魔法少女ユウコが剣と魔法で戦う女性主人公の横スクロールアクション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (436,N'Vita/A',N'',N'厄痛/呪いのゲーム',1,N'"厄痛/呪いのゲーム"',N'アイディアファクトリー',N'',N'AVG',N'',N'',N'SCEJのPS1用ホラーゲーム「厄」シリーズ第2作。呪いのゲームとして主人公に降り注ぐ不運を舞台に進む独特のホラーゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (437,N'Vita',N'',N'メモリーズオフ6/complete',1,N'"メモリーズオフ6/Next Relation"',N'MAGES.(5pb.)',N'',N'AVG',N'',N'',N'KIDのアドベンチャーゲーム「メモリーズオフ6 T-Wave」のPS Vita版完全版。本編に追加シナリオを加え完結させた完全版で、音 楽をテーマにした恋愛アドベンチャー。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (437,N'Vita',N'',N'メモリーズオフ6/complete',2,N'"メモリーズオフ6/T-Wave"',N'MAGES.(5pb.)',N'',N'AVG',N'',N'',N'KID のアドベンチャーゲーム「メモリーズオフ6 T-Wave」のPS Vita版完全版。本編に追加シナリオを加え完結させた完全版で、音楽をテ ーマにした恋愛アドベンチャー。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (438,N'Vita',N'',N'''&''(アンパサンド)/空の向こうで咲きますように',1,N'"''&''(アンパサンド)/空の向こうで咲きますように"',N'MAGES.(5pb.)',N'',N'AVG',N'',N'',N'RejetのPS Vita用ビジュアルノベル「アンパサンド」。空の向こうに誰かと交わった夢のような縁を描く恋愛アドベンチャー。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (439,N'Vita',N'',N'CHAOS;CHILD (カオスチャイルド)',1,N'"CHAOS;CHILD (カオスチャイルド)"',N'MAGES.(5pb.)',N'',N'AVG',N'',N'',N'5pbのPS Vita用サイエンスADV「科学アドベンチャー」シリーズ。「CHAOS;HEAD」の続編で渋谷で起きる連続猟奇殺人を追 う大学新聞部の物語。妄想を現実に具現化する「妄想トリガー」が特徴。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (440,N'Vita',N'',N'EVE/バーストエラーR',1,N'"EVE/バーストエラーR"',N'El Dia',N'',N'AVG',N'',N'',N'C''sWareのビジュア ルノベル「EVE burst error」のPS Vita版リマスター。マリナとコウジという2人の視点から謎の事件を解く推理ADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (441,N'Vita',N'',N'FIFAワールドクラスサッカー',1,N'"FIFAワールドクラスサッカー"',N'EA',N'',N'スポーツ',N'',N'',N'EA のPS Vita用サッカーゲーム「FIFAワールドクラスサッカー」。世界中のサッカーチームが登場するPS Vita版サッカーシミュレーション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (442,N'Vita',N'',N'GRAVITY DAZE/ 重力的眩暈:上層への帰還において、彼女の内宇宙に生じた摂動',1,N'"GRAVITY DAZE/ 重力的 眩暈:上層への帰還において、彼女の内宇宙に生じた摂動"',N'SCE',N'',N'アクション',N'',N'',N'SCEJのPS Vita用オープンワールドアクション。重力を操る特殊能力を持つ少女キトゥンが主人公。落下方向を自在に変えながら空中都市を縦横無尽に飛び回りアクションバトルを繰り広げる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (443,N'Vita',N'',N'STEINS；GATE 0 (シュタインズ・ゲート・ゼロ)',1,N'"STEINS；GATE 0 (シュタインズ・ゲート・ゼロ)"',N'MAGES.(5pb.)',N'',N'AVG',N'',N'',N'5pbとニトロプラスのPS Vita用ビジュアルノベル「シュタインズゲート」の続編。悲劇の運命を変えることを諦めた岡部倫太郎が別の選択をする物語。人工知能「アマデウス」が重要な役割を果たす。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (444,N'Vita',N'',N'STEINS;GATE(シュタインズゲート)',1,N'"STEINS;GATE(シュタインズゲート)"',N'5pb.',N'',N'AVG',N'',N'',N'5pbとニトロプラスのPS Vita用ビジュアルノベル。タイムマシンを発明してしまった大学生・岡部倫太郎が絶対に変えられない運命に挑む。「タイムリープ」を巡る絶望と希望のサイエンスADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (445,N'Vita',N'',N'STEINS;GATE/比翼恋理のだーりん(シュタインズゲート/ひよくれんりのだーりん)',1,N'"STEINS;GATE/比翼恋 理のだーりん(シュタインズゲート/ひよくれんりのだーりん)"',N'5pb.',N'',N'AVG',N'',N'',N'「シュタインズゲート」のPS Vita用ファンディスク。本編のパラレルワールドを舞台に各ヒロインとの恋愛エピソードを楽しめる。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (446,N'Vita',N'',N'STEINS;GATE/線形拘束のフェノグラム',1,N'"STEINS;GATE/線形拘束のフェノグラム"',N'5pb.',N'',N'AVG',N'',N'',N'「シュタインズゲート」のPS Vita用外伝作品。本編キャラそれぞれの視点から語られる複数のサイドストーリーを収録。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (447,N'Vita',N'',N'The Swapper',1,N'"The Swapper"',N'Curve Digital',N'',N'パズル',N'',N'',N'Facepalm GamesのPS Vita 用パズルアドベンチャー。宇宙ステーションを舞台に自分のクローンを作り複数のクローンを同時に操作して謎を解くユニークなシステムのパズルゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (448,N'Vita',N'',N'XBLAZE/CODE:EMBRYO',1,N'"XBLAZE/CODE:EMBRYO"',N'アークシステムワークス',N'',N'AVG',N'',N'',N'アークシステムワークスのPS Vita用「ブレイブルー」世界観を共有したビジュアルノベル。研究者レイチェルとその仲間が謎の事件に挑 む。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (449,N'Vita',N'',N'アーシャのアトリエPlus',1,N'"アーシャのアトリエPlus"',N'コーエーテクモ',N'',N'RPG',N'',N'',N'ガストのPS Vita用RPG「アーランド」三部作後の「黄昏」シリーズ第1作。錬金術が廃れた「黄昏の世界」で行方不明の姉を探す薬師アー シャが成長する物語。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (450,N'Vita',N'',N'アイドルデスゲームTV',1,N'"アイドルデスゲームTV"',N'ディースリー・パブリッシャー',N'',N'SLG',N'',N'',N'パープルソフトウェアのPS Vita用アドベンチャー「アイドルデスゲームTV」。アイドルたちが謎のデスゲームに参加させられ るサスペンスADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (451,N'Vita',N'',N'蒼の彼方のフォーリズム',1,N'"蒼の彼方のフォーリズム"',N'sprite',N'',N'AVG',N'',N'',N'spriteのビジュアルノベルのPS Vita版。「フライングサーカス」という空中を自由に飛べる重力制御装置を使ったスポーツを題材にした青春恋愛ADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (452,N'Vita',N'',N'アルカナハート3/LOVE MAX!!!!!',1,N'"アルカナハート3/LOVE MAX!!!!!"',N'アークシステムワークス',N'',N'格闘',N'',N'',N'エグゼクリエイトのPS Vita用2D格闘ゲーム「アルカナハート」シリーズ第3作の拡張版。女の子キャラクターだ けが登場するアクション格闘ゲーム。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (453,N'Vita',N'',N'アルノサージュPLUS/生まれいずる星へ祈る詩',1,N'"アルノサージュPLUS/生まれいずる星へ祈る詩"',N'コーエ ーテクモ',N'',N'RPG',N'',N'',N'ガストのPS Vita用RPG「サージュ」シリーズ第1弾。現実世界から遠く離れた星に取り残された少女イオンに歌を送り、共に宇宙の謎を解くRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (454,N'Vita',N'',N'アンチャーテッド/地図なき冒険の始まり',1,N'"アンチャーテッド/地図なき冒険の始まり"',N'SCE',N'',N'ア クション',N'',N'',N'SCEとNaughty DogのPS Vita用アクションアドベンチャー「アンチャーテッド」シリーズのPS Vita専用作品 。若きドレイクが幻の島をめぐる事件に巻き込まれる冒険ADV。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (455,N'Vita',N'',N'イース/セルセタの樹海',1,N'"イース/セルセタの樹海"',N'日本ファルコム',N'',N'RPG',N'',N'',N'日本ファルコムのPS Vita用アクションRPG。「イース」シリーズを一新したPS Vita専用新作。記憶を失ったアドルがセルセタの樹海を仲間 と共に探索する。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (456,N'Vita',N'',N'イース8/ラクリモサ・オブ・ダーナ',1,N'"イース8/ラクリモサ・オブ・ダーナ"',N'日本ファルコム',N'',N'RPG',N'',N'',N'日本ファルコムのPS Vita用アクションRPG「イース」シリーズ第8弾。謎の孤島に漂流したアドルが島の生存者たち と協力しながら島の秘密を探る。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (457,N'Vita',N'',N'討鬼伝',1,N'"討鬼伝"',N'コーエーテクモ',N'',N'アクション',N'',N'',N'コーエーテクモのPS Vita用和風ハンティングアクション。「鬼」と呼ばれる怪物を狩猟し「鬼ノ血」を使って強化していく和風テイストのハンティングアクション。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (458,N'Vita',N'',N'英雄伝説/零の軌跡Evolution',1,N'"英雄伝説/零の軌跡Evolution"',N'日本ファルコム',N'',N'RPG',N'',N'',N'日本ファルコムのPS Vita用RPG「零の軌跡」のPS Vita改善版。クロスベル自治州を舞台に警察組織の特殊支援課SSS編が活躍するRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (459,N'Vita',N'',N'英雄伝説/閃の軌跡',1,N'"英雄伝説/閃の軌跡"',N'日本ファルコム',N'',N'RPG',N'',N'',N'日本ファルコムのPS Vita用RPG「閃の軌跡」シリーズ第1作。エレボニア帝国の士官学院を舞台に特別実習班Ⅶ組の物語を描く。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (460,N'Vita',N'',N'英雄伝説/閃の軌跡2',1,N'"英雄伝説/閃の軌跡2"',N'日本ファルコム',N'',N'RPG',N'',N'',N'日本ファルコムのPS Vita用RPG「閃の軌跡」シリーズ第2作。前作の続編で内乱後の帝国を舞台にリィンたちが戦う。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (461,N'Vita',N'',N'エクステトラ',1,N'"エクステトラ"',N'フリュー',N'',N'RPG',N'',N'',N'マーベラスのPS Vita用RPG「エクステトラ」。独特のダンジョン探索システムを持つダンジョンRPG。',N'',N'',N'',N'');
INSERT INTO dbo.TBL_PSLIB (no,platform,enhanced,title,count,notes_titles,publisher,developer,genre,price,release_date,description,url,notes,ps_plus,package) VALUES (462,N'Vita',N'',N'エスケーププラン',1,N'"エスケーププラン"',N'SCE',N'',N'アクション',N'',N'',N'ルーメンズ・ロジックのPS Vita用パズルゲーム。漆黒の液体から小さなキャラクターを脱出させるシンプルなタッチ操作のアクションパズル。',N'',N'',N'',N'');
